from ....structs import ProtocolEntity, ProtocolTreeNode
from typing import Optional, Any, List, Dict, Union
from .ib import IbProtocolEntity
import base64

class KeystoreAttestationIbProtocolEntity(IbProtocolEntity):
    '''
    <ib>
        <keystore_attestation>
            
        </keystore_attestation>
    </ib>

    '''
    def __init__(self, payload) -> None:
        super().__init__()
        self.payload = payload
            
    def toProtocolTreeNode(self) -> Any:
        node = super().toProtocolTreeNode()
        payloadNode = ProtocolTreeNode("keystore_attestation",data=self.payload)
        node.addChild(payloadNode)
        return node

    def __str__(self):
        out = super().__str__()
        out += "ib-keystore_attestation: %s\n" % base64.b64encode(self.payload)
        return out
